```typescript
function solve(nums: number[]): boolean {
    const n = nums.length;

    function isStrictlyIncreasing(start: number, end: number): boolean {
        for (let i = start; i < end; i++) {
            if (nums[i] >= nums[i + 1]) {
                return false;
            }
        }
        return true;
    }

    function isStrictlyDecreasing(start: number, end: number): boolean {
        for (let i = start; i < end; i++) {
            if (nums[i] <= nums[i + 1]) {
                return false;
            }
        }
        return true;
    }

    for (let p = 1; p <= n - 3; p++) {
        if (isStrictlyIncreasing(0, p)) {
            for (let q = p + 1; q <= n - 2; q++) {
                if (isStrictlyDecreasing(p, q) && isStrictlyIncreasing(q, n - 1)) {
                    return true;
                }
            }
        }
    }

    return false;
}
